import string
MOD=2**32
alphabet=string.ascii_letters+string.digits

def jhash(s):
    h=0
    for ch in s:
        h=(31*h+ord(ch))&0xffffffff
    return h

target=jhash('Pas$ion')
print('target',target)
for npre,nsuf in [(3,4),(4,3),(2,5),(5,2)]:
    pow_suf=pow(31,nsuf,MOD)
    print('trying split',npre,nsuf)
    # build suffix map
    suffix_map={}
    total=0
    if nsuf==4:
      for a in alphabet:
        for b in alphabet:
          for c in alphabet:
            for d in alphabet:
              s=a+b+c+d
              h=jhash(s)
              suffix_map.setdefault(h,s)
              total+=1
    elif nsuf==3:
      for a in alphabet:
        for b in alphabet:
          for c in alphabet:
            s=a+b+c
            h=jhash(s)
            suffix_map.setdefault(h,s)
            total+=1
    elif nsuf==5:
      # too big plain, skip
      continue
    elif nsuf==2:
      for a in alphabet:
        for b in alphabet:
          s=a+b
          h=jhash(s)
          suffix_map.setdefault(h,s)
          total+=1
    print('suffix count',total,'unique',len(suffix_map))
    def prefixes(n):
      if n==2:
        for a in alphabet:
          for b in alphabet:
            yield a+b
      elif n==3:
        for a in alphabet:
          for b in alphabet:
            for c in alphabet:
              yield a+b+c
      elif n==4:
        for a in alphabet:
          for b in alphabet:
            for c in alphabet:
              for d in alphabet:
                yield a+b+c+d
      elif n==5:
        for a in alphabet:
          for b in alphabet:
            for c in alphabet:
              for d in alphabet:
                for e in alphabet:
                  yield a+b+c+d+e
    checked=0
    for p in prefixes(npre):
      checked+=1
      hp=jhash(p)
      need=(target - (hp*pow_suf)) & 0xffffffff
      s=suffix_map.get(need)
      if s:
        cand=p+s
        if cand.isalnum() and jhash(cand)==target and cand!='Pas$ion':
          print('FOUND',cand)
          raise SystemExit
      if checked % 1000000==0:
        print('checked',checked)
print('done no find')
