package coffee;
import java.io.*;
import java.util.Base64;

class Bean implements Serializable {
  private static final long serialVersionUID = 1L;
  public Bean inherit;
  public String name;
  public Bean parent1;
  public Bean parent2;
}
class CovfefeBean extends Bean implements Serializable { private static final long serialVersionUID = 1L; }
class DennisBean extends Bean implements Serializable { private static final long serialVersionUID = 1L; }
class GhostBean extends Bean implements Serializable { private static final long serialVersionUID = 1L; }
class HyperBean extends Bean implements Serializable { private static final long serialVersionUID = 1L; }
class MGBean extends Bean implements Serializable { private static final long serialVersionUID = 1L; }
class PassionBean extends Bean implements Serializable { private static final long serialVersionUID = 1L; }
class RaidBean extends Bean implements Serializable { private static final long serialVersionUID = 1L; }
class TnekBean extends Bean implements Serializable { private static final long serialVersionUID = 1L; }
class YeetBean extends Bean implements Serializable { private static final long serialVersionUID = 1L; }

public class BeanTool {
  static Object fromName(String n) throws Exception { return Class.forName("coffee."+n).getDeclaredConstructor().newInstance(); }
  static void dump(Bean b, String p) {
    if (b==null) { System.out.println(p+"null"); return; }
    System.out.println(p+b.getClass().getName()+" name="+b.name);
    if (b.inherit!=null) dump(b.inherit,p+"  inherit-> ");
    if (b.parent1!=null) dump(b.parent1,p+"  p1-> ");
    if (b.parent2!=null) dump(b.parent2,p+"  p2-> ");
  }
  public static void main(String[] args) throws Exception {
    if (args[0].equals("decode")) {
      byte[] data=Base64.getDecoder().decode(args[1]);
      ObjectInputStream ois=new ObjectInputStream(new ByteArrayInputStream(data));
      Bean b=(Bean)ois.readObject();
      dump(b,"");
    } else if (args[0].equals("encode")) {
      Bean b=(Bean)fromName(args[1]);
      b.name=args[2].equals("null")?null:args[2];
      if (!args[3].equals("null")) {
        Bean i=(Bean)fromName(args[3]); i.name=args[4].equals("null")?null:args[4]; b.inherit=i;
      }
      if (!args[5].equals("null")) {
        Bean p1=(Bean)fromName(args[5]); p1.name=args[6].equals("null")?null:args[6]; b.parent1=p1;
      }
      if (!args[7].equals("null")) {
        Bean p2=(Bean)fromName(args[7]); p2.name=args[8].equals("null")?null:args[8]; b.parent2=p2;
      }
      ByteArrayOutputStream bos=new ByteArrayOutputStream();
      ObjectOutputStream oos=new ObjectOutputStream(bos); oos.writeObject(b); oos.close();
      System.out.print(Base64.getEncoder().encodeToString(bos.toByteArray()));
    }
  }
}

