import requests,re
s=requests.Session()
html=s.get('http://172.20.0.2:8080/breed.jsp').text
opts=[]
for val,name in re.findall(r'<option value="([^"]+)">([^<]+)</option>',html):
    if (val,name) not in opts:
        opts.append((val,name))
s.post('http://172.20.0.2:8080/roaster.jsp',data={'bean-name':'test','bean-desc':'desc','parent1':opts[0][0],'parent2':opts[1][0]})
h=s.get('http://172.20.0.2:8080/').text.splitlines()
for i,line in enumerate(h):
    if 'test' in line or '>Flag<' in line:
        for j in range(max(0,i-4), min(len(h), i+8)):
            print(f'{j}: {h[j]}')
        print('---')
PY

